  `comment_count` bigint(20) NULL DEFAULT NULL COMMENT '评论数',
  `share_count` bigint(20) NULL DEFAULT NULL COMMENT '分享数',
  `sales_count` bigint(20) NULL DEFAULT NULL COMMENT '销量',
  `sales_amount` decimal(20, 2) NULL DEFAULT NULL COMMENT '销售额',
  `follower_count` bigint(20) NULL DEFAULT NULL COMMENT '作者粉丝数',
  `range_sales_min` bigint(20) NULL DEFAULT NULL COMMENT '销量范围最小值',
  `range_sales_max` bigint(20) NULL DEFAULT NULL COMMENT '销量范围最大值',
