  `range_amount_max` decimal(20, 2) NULL DEFAULT NULL COMMENT '销售额范围最大值',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_goods_id`(`goods_id` ASC) USING BTREE,
  INDEX `idx_aweme_id`(`aweme_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_sales_amount`(`sales_amount` ASC) USING BTREE,
  INDEX `idx_play_count`(`play_count` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1249 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '视频列表（清洗后）' ROW_FORMAT = Dynamic;

