DROP TABLE IF EXISTS `goods_list`;
CREATE TABLE `goods_list`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `goods_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '内部商品ID',
  `product_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '抖音商品ID',
  `platform` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'douyin' COMMENT '平台',
  `status` tinyint(4) NULL DEFAULT 1 COMMENT '状态',
  `title` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商品标题',
  `cover` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图URL',
  `url` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商品链接',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT '商品价格',
  `coupon` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '优惠券金额',
  `coupon_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '券后价格',
  `cos_ratio` decimal(5, 4) NULL DEFAULT NULL COMMENT '佣金比例',
  `kol_cos_ratio` decimal(5, 4) NULL DEFAULT NULL COMMENT '达人佣金比例',
  `cos_fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '佣金金额',
  `kol_cos_fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '达人佣金金额',
  `cate_0` int(11) NULL DEFAULT NULL COMMENT '类目0',
  `first_cid` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '一级类目ID',
  `second_cid` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '二级类目ID',
  `third_cid` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '三级类目ID',
  `subsidy_status` tinyint(4) NULL DEFAULT 0 COMMENT '补贴状态',
  `subsidy_ratio` decimal(5, 4) NULL DEFAULT 0.0000 COMMENT '补贴比例',
  `butie_rate` decimal(5, 4) NULL DEFAULT 0.0000 COMMENT '补贴率',
  `other_platform` tinyint(4) NULL DEFAULT 0 COMMENT '是否其他平台',
  `shop_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '店铺ID',
  `shop_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '店铺名称',
  `shop_logo` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '店铺Logo',
  `sharable` tinyint(4) NULL DEFAULT 1 COMMENT '是否可分享',
  `is_redu` tinyint(4) NULL DEFAULT 1 COMMENT '是否热度商品',
  `begin_time` date NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` date NULL DEFAULT NULL COMMENT '结束时间',
  `in_stock` tinyint(4) NULL DEFAULT 1 COMMENT '是否有货',
  `view_num` int(11) NULL DEFAULT 0 COMMENT '浏览量',
  `order_num` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '订单数范围',
  `combined` int(11) NULL DEFAULT 0 COMMENT '综合评分',
  `sales_24` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '24小时销量',
  `kol_num` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '达人数量',
  `sales` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '总销量',
  `is_sole` tinyint(4) NULL DEFAULT 0 COMMENT '是否独家',
  `sales_7day` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '7天销量',
  `order_count` int(11) NULL DEFAULT 0 COMMENT '订单数',
  `pay_amount` decimal(15, 2) NULL DEFAULT 0.00 COMMENT '支付金额',
  `service_fee` decimal(15, 2) NULL DEFAULT 0.00 COMMENT '服务费',
  `activity_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '活动ID',
  `kol_weekday` int(11) NULL DEFAULT 0 COMMENT '达人工作日',
  `said` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'SAID',
  `favorite_id` int(11) NULL DEFAULT 0 COMMENT '收藏ID',
  `issue_ratio` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '问题比例',
  `labels` json NULL COMMENT '标签列表',
  `tags` json NULL COMMENT '标记',
  `imgs` json NULL COMMENT '图片列表',
  `shop_total_score` json NULL COMMENT '店铺总评分',
  `raw_data` json NULL COMMENT '原始完整数据',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_product_id`(`product_id` ASC) USING BTREE,
  INDEX `idx_product_id`(`product_id` ASC) USING BTREE,
  INDEX `idx_goods_id`(`goods_id` ASC) USING BTREE,
  INDEX `idx_shop_id`(`shop_id` ASC) USING BTREE,
  INDEX `idx_activity_id`(`activity_id` ASC) USING BTREE,
  INDEX `idx_price`(`price` ASC) USING BTREE,
  INDEX `idx_cos_fee`(`cos_fee` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '商品列表数据表' ROW_FORMAT = DYNAMIC;

